DEFAULT_ADDON_DIR = r"D:\Lich King\Interface\AddOns"

BOLD   = "\033[1m"
GREEN  = "\033[32m"
YELLOW = "\033[33m"
RED    = "\033[31m"
CYAN   = "\033[36m"
DIM    = "\033[2m"
RESET  = "\033[0m"

def cprint(color, msg):
    print(f"{color}{msg}{RESET}")

def progress_hook(block_num, block_size, total_size):
    if total_size > 0:
        pct = min(100, block_num * block_size * 100 // total_size)
        bar = "#" * (pct // 5) + "-" * (20 - pct // 5)
        print(f"\r  [{bar}] {pct:3d}%", end="", flush=True)

def download_file(url, dest_path):
    headers = {"User-Agent": "WoW-Addon-Installer/1.0"}
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req) as response, open(dest_path, "wb") as f:
        total = int(response.headers.get("Content-Length", 0))
        downloaded = 0
        chunk = 65536
        while True:
            data = response.read(chunk)
            if not data:
                break
            f.write(data)
            downloaded += len(data)
            if total:
                pct = min(100, downloaded * 100 // total)
                bar = "#" * (pct // 5) + "-" * (20 - pct // 5)
                print(f"\r  [{bar}] {pct:3d}%", end="", flush=True)
    print()  # newline after progress

def is_github_wrapper(folder_name):
    """Return True if this looks like a GitHub archive wrapper, e.g. repo-main, repo-master, repo-335."""
    return bool(re.search(r'[-_](main|master|\d+(?:\.\d+)*)$', folder_name, re.IGNORECASE))


def extract_archive(archive_path, addon_name, addons_dir):
    """
    Extract zip or rar into addons_dir using these rules:

    GitHub-wrapped archives (single top-level folder ending in -main/-master/-335/etc):
      Strip the wrapper, then apply the same rule as plain zips to the contents.

    Both plain and github-wrapped zips follow this rule:
      - Loose .lua/.toc files at root ‚Üí wrap everything in AddOns/<addon_name>/
        e.g. Auctionator-main/ has only Auctionator/ inside  ‚Üí AddOns/Auctionator/
        e.g. MyAddon-main/     has Core.lua, MyAddon.toc     ‚Üí AddOns/MyAddon/
      - Only sub-folders at root (no loose lua/toc)          ‚Üí drop each folder into AddOns/
        e.g. Bagnon-main/ has Bagnon/, BagnonConfig/         ‚Üí AddOns/Bagnon/ + AddOns/BagnonConfig/
        e.g. ACP.zip      has ACP/                           ‚Üí AddOns/ACP/

    RAR files: extract directly into addons_dir.
    """
    ext = os.path.splitext(archive_path)[1].lower()

    if ext == ".zip":
        with zipfile.ZipFile(archive_path, "r") as zf:
            members = zf.namelist()

            # Work out what sits at the top level of the zip
            top_dirs  = {m.split("/")[0] for m in members if "/" in m and m.split("/")[0]}
            top_files = [m for m in members if "/" not in m.rstrip("/") and m.strip("/")]

            with tempfile.TemporaryDirectory() as tmp:
                zf.extractall(tmp)
                src = tmp

                # Detect a GitHub-style wrapper (single top-level folder named repo-main etc.)
                github_wrapped = (
                    len(top_dirs) == 1
                    and not top_files
                    and is_github_wrapper(list(top_dirs)[0])
                )

                def has_lua_or_toc(file_list):
                    return any(f.endswith((".lua", ".toc")) for f in file_list)

                if github_wrapped:
                    # Strip the wrapper ‚Äî src now points inside it
                    src = os.path.join(tmp, list(top_dirs)[0])

                # Keep stripping wrapper-like single folders until we reach real content.
                # e.g. Bagnon-3.3.5-main/ ‚Üí Bagnon-3.3.5/ ‚Üí Bagnon/, BagnonConfig/, ...
                for _ in range(5):
                    inner = os.listdir(src)
                    inner_dirs  = [i for i in inner if os.path.isdir(os.path.join(src, i))]
                    inner_files = [i for i in inner if os.path.isfile(os.path.join(src, i))]
                    if len(inner_dirs) == 1 and not has_lua_or_toc(inner_files):
                        only = inner_dirs[0]
                        only_path = os.path.join(src, only)
                        # Peek inside: if it contains multiple folders or lua/toc files,
                        # this IS the real content ‚Äî stop here
                        sub = os.listdir(only_path)
                        sub_dirs  = [s for s in sub if os.path.isdir(os.path.join(only_path, s))]
                        sub_files = [s for s in sub if os.path.isfile(os.path.join(only_path, s))]
                        if len(sub_dirs) > 1 or has_lua_or_toc(sub_files):
                            # The single folder IS the addon (e.g. ACP/ACP.toc) or
                            # contains multiple sub-addons ‚Äî stop stripping here
                            break
                        # It's another wrapper layer ‚Äî descend into it
                        src = only_path
                    else:
                        break

                # Re-read after any extra unwrapping
                inner_items = os.listdir(src)
                inner_dirs  = [i for i in inner_items if os.path.isdir(os.path.join(src, i))]
                inner_files = [i for i in inner_items if os.path.isfile(os.path.join(src, i))]

                def addon_folder_count(folder_path):
                    """Count how many immediate sub-folders contain a .toc file (real addons)."""
                    count = 0
                    for item in os.listdir(folder_path):
                        item_path = os.path.join(folder_path, item)
                        if os.path.isdir(item_path):
                            if any(f.endswith(".toc") for f in os.listdir(item_path)):
                                count += 1
                    return count

                if not inner_dirs or has_lua_or_toc(inner_files):
                    # Loose lua/toc at root ‚Üí wrap in AddOns/<addon_name>/
                    dest = os.path.join(addons_dir, addon_name)
                    if os.path.exists(dest):
                        shutil.rmtree(dest)
                    shutil.copytree(src, dest)
                elif len(inner_dirs) == 1:
                    only = inner_dirs[0]
                    only_path = os.path.join(src, only)
                    sub_dirs = [i for i in os.listdir(only_path)
                                if os.path.isdir(os.path.join(only_path, i))]
                    sub_files = [i for i in os.listdir(only_path)
                                 if os.path.isfile(os.path.join(only_path, i))]
                    if len(sub_dirs) > 1 and not has_lua_or_toc(sub_files):
                        # Single folder that itself contains multiple addon sub-folders
                        # (e.g. Bagnon-3.3.5-main/ ‚Üí only Bagnon-3.3.5/ ‚Üí Bagnon/, BagnonConfig/)
                        # Drop each sub-folder straight into AddOns/
                        for item in sub_dirs:
                            clean = re.sub(r'[-_](main|master|\d+(?:\.\d+)*)$', '',
                                          item, flags=re.IGNORECASE)
                            s = os.path.join(only_path, item)
                            d = os.path.join(addons_dir, clean)
                            if os.path.exists(d):
                                shutil.rmtree(d) if os.path.isdir(d) else os.remove(d)
                            shutil.move(s, d)
                    else:
                        # Single addon folder ‚Üí rename to catalogue name
                        s = only_path
                        d = os.path.join(addons_dir, addon_name)
                        if os.path.exists(d):
                            shutil.rmtree(d) if os.path.isdir(d) else os.remove(d)
                        shutil.move(s, d)
                else:
                    # Multiple sub-folders ‚Üí drop each into AddOns/, stripping suffixes
                    for item in inner_dirs:
                        clean = re.sub(r'[-_](main|master|\d+(?:\.\d+)*)$', '',
                                      item, flags=re.IGNORECASE)
                        s = os.path.join(src, item)
                        d = os.path.join(addons_dir, clean)
                        if os.path.exists(d):
                            shutil.rmtree(d) if os.path.isdir(d) else os.remove(d)
                        shutil.move(s, d)

    elif ext == ".rar":
        if not RAR_SUPPORT:
            raise RuntimeError(
                "RAR support not available. Install 'rarfile' and the unrar/7z tool:\n"
                "  pip install rarfile\n"
                "  # Windows: install WinRAR or 7-Zip and ensure unrar.exe is on PATH\n"
                "  # Linux:   sudo apt install unrar"
            )
        with rarfile.RarFile(archive_path) as rf:
            rf.extractall(addons_dir)
    else:
        raise ValueError(f"Unsupported archive format: {ext}")


