# Interactive checkbox selection (curses UI)
# ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

def _curses_picker(stdscr, addons):
    """
    Full-screen curses picker.
    Returns a list of selected (name, desc, url) tuples.

    Keys:
      ‚Üë / ‚Üì / Page Up / Page Down  ‚Äì navigate
      Space                         ‚Äì toggle selection
      A                             ‚Äì select all / deselect all
      /                             ‚Äì search / filter
      Esc                           ‚Äì clear search
      Enter                         ‚Äì confirm and install
      Q                             ‚Äì quit without installing
    """
    curses.curs_set(0)
    curses.start_color()
    curses.use_default_colors()
    curses.init_pair(1, curses.COLOR_CYAN,    -1)  # header
    curses.init_pair(2, curses.COLOR_GREEN,   -1)  # checked
    curses.init_pair(3, curses.COLOR_YELLOW,  -1)  # cursor row
    curses.init_pair(4, curses.COLOR_WHITE,   -1)  # normal
    curses.init_pair(5, curses.COLOR_RED,     -1)  # rar tag / search bar

    checked  = set()   # indices into `addons` that are ticked
    cursor   = 0       # index into filtered list
    scroll   = 0       # top row of visible window
    query    = ""      # current search string
    searching = False

    def filtered():
        if not query:
            return list(enumerate(addons))  # (orig_idx, addon)
        q = query.lower()
        return [(i, a) for i, a in enumerate(addons)
                if q in a[0].lower() or q in a[1].lower()]

    while True:
        rows, cols = stdscr.getmaxyx()
        # Reserve rows: 3 header + 1 search + 1 footer = 5
        list_rows = rows - 5
        visible = filtered()

        # Clamp cursor
        if cursor >= len(visible):
            cursor = max(0, len(visible) - 1)
        # Scroll to keep cursor visible
        if cursor < scroll:
            scroll = cursor
        if cursor >= scroll + list_rows:
            scroll = cursor - list_rows + 1

        stdscr.erase()

        # ‚îÄ‚îÄ Header ‚îÄ‚îÄ
        header = " WoW 3.3.5a Addon Installer  ‚îÇ  Space=tick  A=all  /=search  Enter=install  Q=quit"
        stdscr.attron(curses.color_pair(1) | curses.A_BOLD)
        stdscr.addstr(0, 0, header[:cols-1].ljust(cols-1))
        stdscr.attroff(curses.color_pair(1) | curses.A_BOLD)

        n_checked = len(checked)
        summary = f" {n_checked} addon{'s' if n_checked != 1 else ''} selected of {len(addons)}"
        stdscr.attron(curses.color_pair(1))
        stdscr.addstr(1, 0, summary[:cols-1])
        stdscr.attroff(curses.color_pair(1))

        stdscr.attron(curses.color_pair(4) | curses.A_DIM)
        stdscr.addstr(2, 0, "‚îÄ" * (cols - 1))
        stdscr.attroff(curses.color_pair(4) | curses.A_DIM)

        # ‚îÄ‚îÄ Addon list ‚îÄ‚îÄ
        for row_i, (orig_idx, (name, desc, url)) in enumerate(visible[scroll:scroll+list_rows]):
            y = 3 + row_i
            is_cursor  = (row_i + scroll == cursor)
            is_checked = orig_idx in checked
            is_rar     = url.endswith(".rar")

            tick = "[x]" if is_checked else "[ ]"
            rar  = " [RAR]" if is_rar else ""
            line = f" {tick} {name:<24} {desc}{rar}"
            line = line[:cols-1].ljust(cols-1)

            if is_cursor:
                attr = curses.color_pair(3) | curses.A_BOLD | curses.A_REVERSE
            elif is_checked:
                attr = curses.color_pair(2) | curses.A_BOLD
            else:
                attr = curses.color_pair(4)

            stdscr.attron(attr)
            stdscr.addstr(y, 0, line)
            stdscr.attroff(attr)

        # ‚îÄ‚îÄ Search bar ‚îÄ‚îÄ
        search_y = rows - 2
        stdscr.attron(curses.color_pair(4) | curses.A_DIM)
        stdscr.addstr(search_y - 1, 0, "‚îÄ" * (cols - 1))
        stdscr.attroff(curses.color_pair(4) | curses.A_DIM)

        if searching or query:
            bar = f" Search: {query}_"
            stdscr.attron(curses.color_pair(5) | curses.A_BOLD)
        else:
            bar = " Press / to search"
            stdscr.attron(curses.color_pair(4) | curses.A_DIM)
        stdscr.addstr(search_y, 0, bar[:cols-1].ljust(cols-1))
        stdscr.attroff(curses.color_pair(5) | curses.A_BOLD)
        stdscr.attroff(curses.color_pair(4) | curses.A_DIM)

        stdscr.refresh()

        # ‚îÄ‚îÄ Input ‚îÄ‚îÄ
        key = stdscr.getch()

        if searching:
            if key in (curses.KEY_ENTER, 10, 13):
                searching = False
            elif key == 27:  # Esc ‚Äì clear search
                query = ""
                searching = False
                cursor = 0
                scroll = 0
            elif key in (curses.KEY_BACKSPACE, 127, 8):
                query = query[:-1]
                cursor = 0
                scroll = 0
            elif 32 <= key <= 126:
                query += chr(key)
                cursor = 0
                scroll = 0
            continue

        # Normal mode
        if key == curses.KEY_UP:
            cursor = max(0, cursor - 1)
        elif key == curses.KEY_DOWN:
            cursor = min(len(visible) - 1, cursor + 1)
        elif key == curses.KEY_PPAGE:  # Page Up
            cursor = max(0, cursor - list_rows)
        elif key == curses.KEY_NPAGE:  # Page Down
            cursor = min(len(visible) - 1, cursor + list_rows)
        elif key == curses.KEY_HOME:
            cursor = 0
        elif key == curses.KEY_END:
            cursor = max(0, len(visible) - 1)
        elif key == ord(" "):
            if visible:
                orig_idx = visible[cursor][0]
                if orig_idx in checked:
                    checked.discard(orig_idx)
                else:
                    checked.add(orig_idx)
                # Advance cursor after ticking
                cursor = min(len(visible) - 1, cursor + 1)
        elif key in (ord("a"), ord("A")):
            if len(checked) == len(addons):
                checked.clear()
            else:
                checked = set(range(len(addons)))
        elif key == ord("/"):
            searching = True
        elif key == 27:  # Esc
            query = ""
            cursor = 0
            scroll = 0
        elif key in (curses.KEY_ENTER, 10, 13):
            return [addons[i] for i in sorted(checked)]
        elif key in (ord("q"), ord("Q")):
            return []


def prompt_selection():
    """Launch the curses picker and return selected addons."""
    try:
        return curses.wrapper(_curses_picker, ADDONS)
    except Exception as e:
        # Fallback: if curses fails (e.g. not a real terminal), tell user
        print(f"{RED}Could not start interactive picker: {e}{RESET}")
        print(f"{YELLOW}Tip: on Windows run  pip install windows-curses  then retry.{RESET}")
        sys.exit(1)


