# Fix existing badly-named folders
# ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

def build_rename_map(addons_dir):
    """
    Scan addons_dir for folders whose names look like GitHub archive wrappers
    (e.g. WoW-3.3.5a-Addons-main, WotLK-Auctionator-main, pretty-minimap-master)
    and try to match them to catalogue addon names.

    Returns a list of (current_path, new_path, catalogue_name) tuples.
    """
    if not os.path.isdir(addons_dir):
        return []

    # Build a lookup: catalogue_name.lower() ‚Üí catalogue_name (display form)
    catalogue = {name.lower(): name for name, _, _ in ADDONS}

    renames = []
    for entry in sorted(os.listdir(addons_dir)):
        full = os.path.join(addons_dir, entry)
        if not os.path.isdir(full):
            continue
        if not is_github_wrapper(entry):
            continue

        # Strip the trailing -main / -master / -version suffix to get the stem
        stem = re.sub(r'[-_](main|master|\d+(?:\.\d+)*)$', '', entry, flags=re.IGNORECASE)

        # Try to match stem against catalogue names (exact then fuzzy)
        matched_display = None

        def normalise(s):
            return s.lower().replace("-", "_")

        norm_cat = {normalise(k): v for k, v in catalogue.items()}

        # 1. Exact match (case-insensitive, hyphen/underscore agnostic)
        if normalise(stem) in norm_cat:
            matched_display = norm_cat[normalise(stem)]
        else:
            # 2. Fuzzy: strip common prefixes like "wotlk-", "wow-", "wow-3.3.5a-"
            cleaned = re.sub(r'^(wotlk|wrath|wow(?:-[\d.]+a?)?|wow-[\d.]+a?)[-_]', '',
                             stem, flags=re.IGNORECASE)
            if normalise(cleaned) in norm_cat:
                matched_display = norm_cat[normalise(cleaned)]
            else:
                # 3. Partial match: stem contains or is contained in a catalogue name
                candidates = [v for k, v in norm_cat.items()
                              if normalise(cleaned) in k or k in normalise(cleaned)]
                if len(candidates) == 1:
                    matched_display = candidates[0]

        if matched_display:
            new_path = os.path.join(addons_dir, matched_display)
            if full != new_path:
                renames.append((full, new_path, matched_display))

    return renames


def run_fix_names(addons_dir):
    """Interactively rename badly-named addon folders to their catalogue names."""
    cprint(BOLD + CYAN, f"\n Scanning: {addons_dir}\n")

    renames = build_rename_map(addons_dir)

    if not renames:
        cprint(GREEN, " No folders need renaming ‚Äî everything looks clean!")
        return

    cprint(BOLD, f" Found {len(renames)} folder(s) to rename:\n")
    for old_path, new_path, _ in renames:
        old_name = os.path.basename(old_path)
        new_name = os.path.basename(new_path)
        print(f"  {YELLOW}{old_name}{RESET}  ‚Üí  {GREEN}{new_name}{RESET}")

    print()
    confirm = input(f"{BOLD}Rename all? [Y/n]: {RESET}").strip().lower()
    if confirm not in ("", "y", "yes"):
        cprint(YELLOW, "Aborted.")
        return

    ok, failed = [], []
    for old_path, new_path, display in renames:
        try:
            if os.path.exists(new_path):
                # Target already exists ‚Äî remove it first
                shutil.rmtree(new_path)
            os.rename(old_path, new_path)
            cprint(GREEN, f"  ‚úî  {os.path.basename(old_path)}  ‚Üí  {display}")
            ok.append(display)
        except Exception as e:
            cprint(RED, f"  ‚úò  {os.path.basename(old_path)}: {e}")
            failed.append((os.path.basename(old_path), str(e)))

    print()
    cprint(BOLD + CYAN, "‚ïê" * 60)
    cprint(GREEN, f"  ‚úî Renamed ({len(ok)}): {', '.join(ok) if ok else '‚Äî'}")
    if failed:
        cprint(RED, f"  ‚úò Failed  ({len(failed)}):")
        for name, reason in failed:
            cprint(RED, f"      ‚Ä¢ {name}: {reason}")
    print()


