def install_addons(addons, install_dir):
    os.makedirs(install_dir, exist_ok=True)
    total = len(addons)
    ok, failed = [], []

    for i, (name, desc, url) in enumerate(addons, 1):
        cprint(BOLD, f"\n[{i}/{total}] {name}")
        print(f"  {DIM}{desc}{RESET}")
        print(f"  URL: {DIM}{url}{RESET}")

        ext = ".rar" if url.endswith(".rar") else ".zip"
        tmp_file = os.path.join(tempfile.gettempdir(), f"wow_addon_{name}{ext}")

        try:
            print(f"  Downloading‚Ä¶")
            download_file(url, tmp_file)

            print(f"  Extracting to {install_dir}‚Ä¶")
            extract_archive(tmp_file, name, install_dir)

            cprint(GREEN, f"  ‚úî {name} installed successfully.")
            ok.append(name)

        except Exception as e:
            cprint(RED, f"  ‚úò Failed: {e}")
            failed.append((name, str(e)))

        finally:
            if os.path.exists(tmp_file):
                os.remove(tmp_file)

    # Summary
    print()
    cprint(BOLD + CYAN, "‚ïê" * 60)
    cprint(BOLD, "Installation summary")
    cprint(BOLD + CYAN, "‚ïê" * 60)
    cprint(GREEN, f"  ‚úî Installed ({len(ok)}): {', '.join(ok) if ok else '‚Äî'}")
    if failed:
        cprint(RED, f"  ‚úò Failed    ({len(failed)}):")
        for name, reason in failed:
            cprint(RED, f"      ‚Ä¢ {name}: {reason}")
    print()


