# Update: check for newer versions then offer to install
# ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

def normalise_name(s):
    return s.lower().replace("-", "_").replace(" ", "_")


def scan_installed(addons_dir):
    """Return catalogue entries whose name matches an installed folder."""
    if not os.path.isdir(addons_dir):
        return []
    installed_folders = {normalise_name(f) for f in os.listdir(addons_dir)
                         if os.path.isdir(os.path.join(addons_dir, f))}
    return [a for a in ADDONS if normalise_name(a[0]) in installed_folders]


def local_install_time(addon_name, addons_dir):
    """
    Return the most recent mtime of any file inside the addon folder,
    as a UTC datetime. Falls back to folder mtime if no files found.
    """
    folder = os.path.join(addons_dir, addon_name)
    if not os.path.isdir(folder):
        return None
    latest = 0.0
    for root, _, files in os.walk(folder):
        for f in files:
            try:
                t = os.path.getmtime(os.path.join(root, f))
                if t > latest:
                    latest = t
            except OSError:
                pass
    if latest == 0.0:
        try:
            latest = os.path.getmtime(folder)
        except OSError:
            return None
    import datetime
    return datetime.datetime.utcfromtimestamp(latest)


def github_last_commit(url):
    """
    Given a download URL, derive the GitHub API commits endpoint and
    return the date of the latest commit as a UTC datetime, or None.

    Handles both:
      raw.githubusercontent.com  (direct file links)
      github.com/‚Ä¶/archive/‚Ä¶    (zip archive links)
    """
    import datetime, json

    # Pattern 1: raw.githubusercontent.com/OWNER/REPO/BRANCH/path
    m = re.match(
        r"https://raw\.githubusercontent\.com/([^/]+/[^/]+)/([^/]+)/",
        url
    )
    if m:
        repo, branch = m.group(1), m.group(2)
        api = f"https://api.github.com/repos/{repo}/commits?sha={branch}&per_page=1"
    else:
        # Pattern 2: github.com/OWNER/REPO/archive/refs/heads/BRANCH.zip
        m = re.match(
            r"https://github\.com/([^/]+/[^/]+)/archive/refs/heads/([^/]+)\.zip",
            url
        )
        if m:
            repo, branch = m.group(1), m.group(2)
            api = f"https://api.github.com/repos/{repo}/commits?sha={branch}&per_page=1"
        else:
            # Pattern 3: github.com/OWNER/REPO/releases/latest/download/‚Ä¶
            m = re.match(r"https://github\.com/([^/]+/[^/]+)/releases/", url)
            if m:
                repo = m.group(1)
                api = f"https://api.github.com/repos/{repo}/releases/latest"
            else:
                return None

    try:
        req = urllib.request.Request(
            api,
            headers={"User-Agent": "WoW-Addon-Installer/1.0",
                     "Accept": "application/vnd.github+json"}
        )
        with urllib.request.urlopen(req, timeout=10) as r:
            data = json.loads(r.read())

        # Commits endpoint returns a list; releases endpoint returns a dict
        if isinstance(data, list) and data:
            date_str = data[0]["commit"]["committer"]["date"]
        elif isinstance(data, dict):
            date_str = data.get("published_at") or data.get("created_at")
        else:
            return None

        # Parse ISO 8601 e.g. "2024-03-15T12:34:56Z"
        date_str = date_str.rstrip("Z")
        return datetime.datetime.strptime(date_str, "%Y-%m-%dT%H:%M:%S")

    except Exception:
        return None


def check_for_updates(installed, addons_dir):
    """
    For each installed addon, fetch the latest GitHub commit date and
    compare against the local install time.

    Returns three lists:
      updates_available  ‚Äì (addon, local_dt, remote_dt)
      up_to_date         ‚Äì (addon, local_dt)
      unknown            ‚Äì addon  (couldn't fetch remote date)
    """
    import datetime
    updates_available, up_to_date, unknown = [], [], []

    total = len(installed)
    for i, addon in enumerate(installed, 1):
        name, _, url = addon
        print(f"  {DIM}[{i}/{total}] Checking {name}‚Ä¶{RESET}", end="\r", flush=True)

        local_dt  = local_install_time(name, addons_dir)
        remote_dt = github_last_commit(url)

        if remote_dt is None:
            unknown.append(addon)
        elif local_dt is None:
            # Folder exists but we couldn't read a time ‚Äî treat as needing update
            updates_available.append((addon, None, remote_dt))
        elif remote_dt > local_dt:
            updates_available.append((addon, local_dt, remote_dt))
        else:
            up_to_date.append((addon, local_dt))

    # Clear the progress line
    print(" " * 60, end="\r")
    return updates_available, up_to_date, unknown


def run_update(addons_dir):
    """Check installed addons for updates, then offer to install them."""
    import datetime

    cprint(BOLD + CYAN, f"\n  Scanning for installed addons in:\n  {addons_dir}\n")

    installed = scan_installed(addons_dir)
    if not installed:
        cprint(YELLOW, "  No recognised addons found in that folder.")
        return

    cprint(BOLD, f"  Found {len(installed)} installed addon(s). Checking for updates‚Ä¶\n")

    updates_available, up_to_date, unknown = check_for_updates(installed, addons_dir)

    def fmt_dt(dt):
        if dt is None:
            return "unknown"
        return dt.strftime("%Y-%m-%d %H:%M") + " UTC"

    # ‚îÄ‚îÄ Report ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    if updates_available:
        cprint(BOLD + YELLOW, f"  ‚¨Ü  {len(updates_available)} update(s) available:\n")
        for addon, local_dt, remote_dt in updates_available:
            name = addon[0]
            local_str  = fmt_dt(local_dt)
            remote_str = fmt_dt(remote_dt)
            print(f"    {YELLOW}‚Ä¢{RESET} {BOLD}{name:<25}{RESET} "
                  f"{DIM}installed {local_str}  ‚Üí  repo {remote_str}{RESET}")
    else:
        cprint(GREEN, "  ‚úî  All addons are up to date!")

    if up_to_date:
        print()
        cprint(GREEN, f"  ‚úî  {len(up_to_date)} already up to date:")
        for addon, local_dt in up_to_date:
            print(f"    {DIM}‚Ä¢ {addon[0]}{RESET}")

    if unknown:
        print()
        cprint(DIM, f"  ?  {len(unknown)} could not be checked (no GitHub API response):")
        for addon in unknown:
            print(f"    {DIM}‚Ä¢ {addon[0]}{RESET}")

    if not updates_available:
        print()
        return

    # ‚îÄ‚îÄ Offer to install ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    print()
    cprint(BOLD, f"  Updates available for: {', '.join(a[0][0] for a in updates_available)}")
    print()
    print(f"    {BOLD}1.{RESET}  Update all {len(updates_available)} addon(s)")
    print(f"    {BOLD}2.{RESET}  Choose which to update")
    print(f"    {BOLD}3.{RESET}  Cancel")
    print()

    while True:
        sub = input(f"  {BOLD}Enter 1, 2 or 3: {RESET}").strip()
        if sub in ("1", "2", "3"):
            break
        cprint(YELLOW, "  Please enter 1, 2 or 3.")

    if sub == "3":
        cprint(YELLOW, "  Cancelled.")
        return

    if sub == "1":
        to_install = [a[0] for a in updates_available]
    else:
        # Curses picker pre-ticked with available updates
        update_addons = [a[0] for a in updates_available]
        to_install = curses.wrapper(_curses_picker, update_addons)

    if not to_install:
        cprint(YELLOW, "  Nothing selected.")
        return

    print()
    install_addons(to_install, addons_dir)


