CONFIG_FILE = os.path.join(os.path.expanduser("~"), ".wow_addon_installer")


def load_saved_dir():
    """Return the previously saved AddOns directory, or None."""
    try:
        with open(CONFIG_FILE) as f:
            path = f.read().strip()
            return path if path else None
    except FileNotFoundError:
        return None


def save_dir(path):
    """Persist the chosen AddOns directory for future runs."""
    try:
        with open(CONFIG_FILE, "w") as f:
            f.write(path)
    except OSError:
        pass


def pick_folder_dialog(title="Select your WoW AddOns folder", initial=None):
    """
    Open a native OS folder-picker dialog using tkinter.
    Returns the chosen path string, or None if cancelled / unavailable.
    """
    try:
        import tkinter as tk
        from tkinter import filedialog
        root = tk.Tk()
        root.withdraw()          # hide the root window
        root.attributes("-topmost", True)
        chosen = filedialog.askdirectory(
            title=title,
            initialdir=initial or os.path.expanduser("~"),
        )
        root.destroy()
        return chosen if chosen else None
    except Exception:
        return None


def resolve_dir(args_dir):
    """
    Determine the AddOns directory with this priority:
      1. --dir flag
      2. Saved config file  (~/.wow_addon_installer)
      3. Native folder-picker dialog  (first run)
      4. Manual text input fallback   (if tkinter unavailable)
    """
    # ‚îÄ‚îÄ 1. CLI flag ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    if args_dir:
        save_dir(args_dir)
        return args_dir

    # ‚îÄ‚îÄ 2. Previously saved directory ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    saved = load_saved_dir()
    if saved and os.path.isdir(saved):
        return saved

    # ‚îÄ‚îÄ 3 & 4. First run ‚Äî ask the user to choose ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    print()
    cprint(BOLD + CYAN, "  Welcome! Please select your WoW AddOns folder.")
    print()

    chosen = pick_folder_dialog("Select your WoW Interface\\AddOns folder")

    if chosen:
        cprint(GREEN, f"  ‚úî AddOns folder set to:\n    {chosen}")
        save_dir(chosen)
        return chosen

    # Tkinter not available ‚Äî fall back to text prompt
    cprint(YELLOW, "  (Folder picker unavailable ‚Äî please type the path instead)")
    raw = input(
        f"\n  {BOLD}AddOns folder path{RESET} {DIM}(Enter = {DEFAULT_ADDON_DIR}){RESET}\n"
        f"  {BOLD}> {RESET}"
    ).strip().strip('"').strip("'")
    path = raw if raw else DEFAULT_ADDON_DIR
    save_dir(path)
    return path


