def main():
    parser = argparse.ArgumentParser(
        description="Install WoW 3.3.5a addons from NoM0Re's GitHub repository.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  python wow_addon_installer.py
      Interactive menu ‚Äî install or update addons.

  python wow_addon_installer.py --dir "C:/WoW/Interface/AddOns" --addons DBM Questie
      Install named addons directly (skips menu).

  python wow_addon_installer.py --dir "C:/WoW/Interface/AddOns" --addons all
      Install every addon in the catalogue.

  python wow_addon_installer.py --list
      Print the full addon list and exit.

  python wow_addon_installer.py --fix-names
      Rename GitHub-style folders to clean catalogue names.
"""
    )
    parser.add_argument("--dir", "-d", metavar="ADDON_DIR",
                        help="Path to your WoW Interface/AddOns folder.")
    parser.add_argument("--addons", "-a", nargs="+", metavar="NAME",
                        help="Addon names to install (use 'all' for everything).")
    parser.add_argument("--list", "-l", action="store_true",
                        help="List all available addons and exit.")
    parser.add_argument("--fix-names", "-f", action="store_true",
                        help="Rename GitHub-style folders to clean catalogue names.")
    args = parser.parse_args()

    # ‚îÄ‚îÄ Non-interactive flags ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    if args.list:
        list_addons()
        return

    if args.fix_names:
        run_fix_names(resolve_dir(args.dir))
        input(f"\n{DIM}  Press Enter to exit‚Ä¶{RESET}")
        return

    # ‚îÄ‚îÄ CLI shortcut: --addons supplied, skip menu ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    if args.addons:
        install_dir = resolve_dir(args.dir)
        if args.addons == ["all"]:
            selected = list(ADDONS)
        else:
            selected = []
            for token in args.addons:
                matches = [a for a in ADDONS if token.lower() in a[0].lower()]
                if not matches:
                    cprint(YELLOW, f"  ‚öÝ  No addon matched: '{token}'")
                selected.extend(matches)
        if selected:
            install_addons(selected, install_dir)
        input(f"\n{DIM}  Press Enter to exit‚Ä¶{RESET}")
        return

    # ‚îÄ‚îÄ Interactive mode ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    print_banner()

    install_dir = resolve_dir(args.dir)

    while True:
        choice = main_menu(install_dir)

        if choice == "1":
            # ‚îÄ‚îÄ Option 1: Install ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
            print()
            cprint(DIM, f"  Default repo: github.com/NoM0Re/WoW-3.3.5a-Addons")
            change = input(f"  {BOLD}Use a different addons repo? [y/N]: {RESET}").strip().lower()
            if change in ("y", "yes"):
                raw = input(
                    f"  {BOLD}New repo URL{RESET} {DIM}(Enter = keep current){RESET}\n"
                    f"  {BOLD}> {RESET}"
                ).strip().strip('"').strip("'")
                if raw:
                    install_dir = raw

            selected = prompt_selection()

            if not selected:
                cprint(YELLOW, "\n  No addons selected.")
            else:
                print()
                cprint(BOLD, f"  About to install {len(selected)} addon(s) into:")
                cprint(CYAN, f"  {install_dir}\n")
                for name, _, _ in selected:
                    print(f"    ‚Ä¢ {name}")
                print()
                confirm = input(f"  {BOLD}Proceed? [Y/n]: {RESET}").strip().lower()
                if confirm in ("", "y", "yes"):
                    install_addons(selected, install_dir)

        elif choice == "2":
            # ‚îÄ‚îÄ Option 2: Update ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
            run_update(install_dir)

        elif choice == "3":
            # ‚îÄ‚îÄ Option 3: Change AddOns folder ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
            print()
            cprint(BOLD, "  Select a new AddOns folder:")
            chosen = pick_folder_dialog("Select your WoW Interface\\AddOns folder",
                                        initial=install_dir)
            if chosen:
                install_dir = chosen
                save_dir(install_dir)
                cprint(GREEN, f"\n  ‚úî AddOns folder updated to:\n    {install_dir}")
            else:
                # Fall back to text input
                raw = input(
                    f"\n  {BOLD}New AddOns folder path{RESET} "
                    f"{DIM}(Enter = keep current){RESET}\n"
                    f"  {BOLD}> {RESET}"
                ).strip().strip('"').strip("'")
                if raw:
                    install_dir = raw
                    save_dir(install_dir)

        # ‚îÄ‚îÄ After finishing, offer to return to menu or exit ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
        print()
        again = input(f"  {BOLD}Return to main menu? [Y/n]: {RESET}").strip().lower()
        if again not in ("", "y", "yes"):
            cprint(CYAN, "\n  Goodbye!\n")
            break


